import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const Login = () => {
  const [address, setAddress] = useState('');
  const [network, setNetwork] = useState('1'); // По умолчанию Ethereum
  const [walletType, setWalletType] = useState('Trust Wallet'); // По умолчанию Trust Wallet
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState('');

  const { login } = useAuth();
  const navigate = useNavigate();

  // Определяем доступные кошельки в зависимости от выбранной сети
  const getAvailableWallets = () => {
    if (network === '1') { // Ethereum
      return ['Trust Wallet'];
    } else if (network === '2') { // TON
      return ['Trust Wallet', 'Tonkeeper'];
    }
    return ['Trust Wallet'];
  };

  // Обработчик изменения сети
  const handleNetworkChange = (e) => {
    const newNetwork = e.target.value;
    setNetwork(newNetwork);

    // Если выбран Ethereum и текущий кошелек - Tonkeeper, меняем на Trust Wallet
    if (newNetwork === '1' && walletType === 'Tonkeeper') {
      setWalletType('Trust Wallet');
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!address || !network || !walletType) {
      setError('Пожалуйста, заполните все поля');
      return;
    }

    try {
      setLoading(true);
      setError('');

      // Используем фиксированную тестовую подпись для демо-режима
      const testSignature = 'test_signature';

      await login(address, network, testSignature, walletType);

      setSuccess(`Вход через ${walletType} выполнен успешно!`);

      // Перенаправляем пользователя на страницу профиля
      setTimeout(() => {
        navigate('/profile');
      }, 1500);

    } catch (error) {
      console.error('Ошибка при входе:', error);
      setError(error.response?.data?.detail || 'Ошибка при попытке входа');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="container">
      <div className="card" style={{ maxWidth: '500px', margin: '40px auto' }}>
        <h2>Вход через криптокошелек</h2>

        {error && <div className="alert alert-danger">{error}</div>}
        {success && <div className="alert alert-success">{success}</div>}

        <form onSubmit={handleSubmit}>
          <div className="form-group">
            <label htmlFor="network" className="form-label">
              Сеть
            </label>
            <select
              id="network"
              className="form-control"
              value={network}
              onChange={handleNetworkChange}
              disabled={loading}
            >
              <option value="1">Ethereum</option>
              <option value="2">TON</option>
            </select>
          </div>

          <div className="form-group">
            <label htmlFor="walletType" className="form-label">
              Тип кошелька
            </label>
            <select
              id="walletType"
              className="form-control"
              value={walletType}
              onChange={(e) => setWalletType(e.target.value)}
              disabled={loading}
            >
              {getAvailableWallets().map(wallet => (
                <option key={wallet} value={wallet}>
                  {wallet}
                </option>
              ))}
            </select>
          </div>

          <div className="form-group">
            <label htmlFor="address" className="form-label">
              Адрес кошелька
            </label>
            <input
              type="text"
              id="address"
              className="form-control"
              value={address}
              onChange={(e) => setAddress(e.target.value)}
              placeholder={network === '1' ? '0x123456789abcdef...' : 'EQA123456789abcdef...'}
              disabled={loading}
              required
            />
          </div>

          <button
            type="submit"
            className="btn"
            style={{ width: '100%' }}
            disabled={loading}
          >
            {loading ? 'Вход...' : `Войти через ${walletType}`}
          </button>
        </form>

        <div style={{ marginTop: '20px', textAlign: 'center', fontSize: '0.9rem' }}>
          <p>
            В этой демо-версии вы можете использовать любой адрес кошелька для входа.
            <br />
            Для Ethereum доступен только Trust Wallet.
            <br />
            Для TON доступны Trust Wallet и Tonkeeper.
          </p>
        </div>
      </div>
    </div>
  );
};

export default Login;
